15	// postLoopback sends a JSON POST to path with body and returns the recorder.
16	// Sets the loopback RemoteAddr so the requireTrusted gate passes.
17	func postLoopback(t *testing.T, srv *Server, path string, body any) *httptest.ResponseRecorder {
18		t.Helper()
19		var buf bytes.Buffer
20		if body != nil {
21			if err := json.NewEncoder(&buf).Encode(body); err != nil {
22				t.Fatalf("encode body: %v", err)
23			}
24		}
25		req := httptest.NewRequest(http.MethodPost, path, &buf)
26		req.Header.Set("Content-Type", "application/json")
27		req.RemoteAddr = "127.0.0.1:54321"
28		w := httptest.NewRecorder()
29		srv.Handler().ServeHTTP(w, req)
30		return w
31	}
