33	// readWorkerEventsLog returns each line of .ddx/server/worker-events.jsonl as
34	// a parsed loggedEvent. Returns an empty slice when the file does not exist.
35	func readWorkerEventsLog(t *testing.T, workingDir string) []loggedEvent {
36		t.Helper()
37		path := filepath.Join(workingDir, ".ddx", "server", "worker-events.jsonl")
38		f, err := os.Open(path)
39		if err != nil {
40			if os.IsNotExist(err) {
41				return nil
42			}
43			t.Fatalf("open events log: %v", err)
44		}
45		defer f.Close()
46		var out []loggedEvent
47		sc := bufio.NewScanner(f)
48		for sc.Scan() {
49			var ev loggedEvent
50			if err := json.Unmarshal(sc.Bytes(), &ev); err != nil {
51				t.Fatalf("decode log line %q: %v", sc.Text(), err)
52			}
53			out = append(out, ev)
54		}
55		if err := sc.Err(); err != nil {
56			t.Fatalf("scan log: %v", err)
57		}
58		return out
59	}
